commands.examples:
START TRANSACTION;
UPDATE accounts SET balance = balance - 100000 WHERE id = 1;
UPDATE accounts SET balance = balance + 100000 WHERE id = 2;
COMMIT;

-- Dengan error handling di procedure
DELIMITER //
CREATE PROCEDURE Transfer(IN from_id INT, IN to_id INT, IN amount DECIMAL(12,2))
BEGIN
  DECLARE EXIT HANDLER FOR SQLEXCEPTION
  BEGIN
    ROLLBACK;
    RESIGNAL;
  END;

  START TRANSACTION;
  UPDATE accounts SET balance = balance - amount WHERE id = from_id;
  UPDATE accounts SET balance = balance + amount WHERE id = to_id;
  COMMIT;
END //
DELIMITER ;

START TRANSACTION;
INSERT INTO orders (user_id, total) VALUES (1, 500000);
SET @order_id = LAST_INSERT_ID();
INSERT INTO order_items (order_id, product_id, qty) VALUES (@order_id, 5, 2);
COMMIT;

START TRANSACTION;
DELETE FROM users WHERE id = 1;
-- Oops! Salah user
ROLLBACK;

START TRANSACTION;
INSERT INTO orders (user_id, total) VALUES (1, 500000);
SAVEPOINT after_order;
INSERT INTO payments (order_id, amount) VALUES (LAST_INSERT_ID(), 500000);
-- Jika payment gagal, rollback ke savepoint
ROLLBACK TO SAVEPOINT after_order;
COMMIT;

LOCK TABLES products WRITE;
UPDATE products SET stock = stock - 1 WHERE id = 5;
UNLOCK TABLES;

-- Row-level locking (lebih baik)
SELECT * FROM products WHERE id = 5 FOR UPDATE;
SELECT * FROM products WHERE id = 5 LOCK IN SHARE MODE;

SET TRANSACTION ISOLATION LEVEL READ COMMITTED;
SELECT @@transaction_isolation;
SET SESSION TRANSACTION ISOLATION LEVEL SERIALIZABLE;
